namespace sv_08273673e3ad46f889fa0634c78c8b8a.Services;

/// <summary>
/// Scoped service that adds a random notification every 15 seconds.
/// Started/stopped by the Dashboard page via Start/Stop.
/// Fires on a Timer thread — subscribers must marshal to UI via InvokeAsync.
/// </summary>
public class SimulatorService : IDisposable
{
    private readonly NotificationHub _hub;
    private Timer? _timer;
    private static readonly string[] Titles =
    [
        "Deployment Complete", "CPU Spike Detected", "New User Registered",
        "Disk Space Low", "Backup Finished", "Service Restarted",
        "SSL Certificate Expiring", "Database Connection Pool Full"
    ];
    private static readonly string[] Messages =
    [
        "Action may be required.", "Review the dashboard for details.",
        "Automated recovery initiated.", "Please investigate promptly.",
        "No further action needed.", "Threshold exceeded for 5 minutes."
    ];

    public SimulatorService(NotificationHub hub)
    {
        _hub = hub;
    }

    public void Start()
    {
        _timer ??= new Timer(AddRandom, null, TimeSpan.FromSeconds(15), TimeSpan.FromSeconds(15));
    }

    public void Stop()
    {
        _timer?.Dispose();
        _timer = null;
    }

    private void AddRandom(object? state)
    {
        var rng = Random.Shared;
        var title = Titles[rng.Next(Titles.Length)];
        var message = Messages[rng.Next(Messages.Length)];
        var severity = (Severity)rng.Next(3);
        _hub.AddNotification(title, message, severity);
    }

    public void Dispose()
    {
        Stop();
    }
}

