@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<div class="notification-bell position-relative d-inline-block px-3 py-2">
    <a href="notifications" class="text-white text-decoration-none">
        <span class="bi bi-bell-fill" aria-hidden="true">🔔</span>
        @if (_unreadCount > 0)
        {
            <span class="badge bg-danger position-absolute top-0 start-100 translate-middle rounded-pill">
                @_unreadCount
            </span>
        }
    </a>
</div>

@code {
    private int _unreadCount;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _unreadCount = Hub.GetUnreadCount();
        // Use InvokeAsync because OnChange may fire from a Timer thread
        _handler = () => InvokeAsync(() =>
        {
            _unreadCount = Hub.GetUnreadCount();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject NotificationHub Hub
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h2>Notifications</h2>

<button class="btn btn-sm btn-outline-primary mb-3" @onclick="Hub.MarkAllRead">
    Mark All Read
</button>

@if (!_grouped.Any())
{
    <p class="text-muted">No notifications.</p>
}
else
{
    @foreach (var group in _grouped)
    {
        <h4 class="mt-3">
            @switch (group.Key)
            {
                case Severity.Critical:
                    <span class="text-danger">⚠ Critical</span>
                    break;
                case Severity.Warning:
                    <span class="text-warning">⚡ Warning</span>
                    break;
                default:
                    <span class="text-info">ℹ Info</span>
                    break;
            }
        </h4>
        <ul class="list-group mb-2">
            @foreach (var n in group)
            {
                <li class="list-group-item d-flex justify-content-between align-items-start @(n.IsRead ? "" : "list-group-item-light fw-bold")">
                    <div>
                        <div>@n.Title</div>
                        <small class="text-muted">@n.Message — @n.Timestamp.ToString("g")</small>
                    </div>
                    <div class="btn-group btn-group-sm">
                        @if (!n.IsRead)
                        {
                            <button class="btn btn-outline-success" @onclick="() => Hub.MarkAsRead(n.Id)">Mark Read</button>
                        }
                        <button class="btn btn-outline-danger" @onclick="() => Hub.DismissNotification(n.Id)">Dismiss</button>
                    </div>
                </li>
            }
        </ul>
    }
}

@code {
    private IEnumerable<IGrouping<Severity, Notification>> _grouped = [];
    private Action? _handler;

    protected override void OnInitialized()
    {
        Refresh();
        _handler = () => InvokeAsync(() =>
        {
            Refresh();
            StateHasChanged();
        });
        Hub.OnChange += _handler;
    }

    private void Refresh()
    {
        _grouped = Hub.Notifications
            .OrderBy(n => n.Severity switch { Severity.Critical => 0, Severity.Warning => 1, _ => 2 })
            .GroupBy(n => n.Severity);
    }

    public void Dispose()
    {
        Hub.OnChange -= _handler;
    }
}

