+@inject NotificationHub Hub
+@implements IDisposable
+
+<div class="card mt-3">
+    <div class="card-header">
+        <strong>Recent Unread Notifications</strong>
+    </div>
+    <div class="card-body">
+        @if (!_recent.Any())
+        {
+            <p class="text-muted mb-0">No unread notifications.</p>
+        }
+        else
+        {
+            <ul class="list-group list-group-flush">
+                @foreach (var n in _recent)
+                {
+                    <li class="list-group-item d-flex justify-content-between align-items-center">
+                        <div>
+                            <span class="@SeverityBadge(n.Severity) me-2">@n.Severity</span>
+                            <strong>@n.Title</strong>
+                            <br /><small class="text-muted">@n.Message</small>
+                        </div>
+                        <button class="btn btn-sm btn-outline-danger" @onclick="() => Hub.DismissNotification(n.Id)">
+                            Dismiss
+                        </button>
+                    </li>
+                }
+            </ul>
+        }
+    </div>
+</div>
+
+@code {
+    private List<Notification> _recent = [];
+    private Action? _handler;
+
+    protected override void OnInitialized()
+    {
+        Refresh();
+        _handler = () => InvokeAsync(() =>
+        {
+            Refresh();
+            StateHasChanged();
+        });
+        Hub.OnChange += _handler;
+    }
+
+    private void Refresh()
+    {
+        _recent = Hub.Notifications
+            .Where(n => !n.IsRead)
+            .OrderByDescending(n => n.Timestamp)
+            .Take(3)
+            .ToList();
+    }
+
+    private static string SeverityBadge(Severity s) => s switch
+    {
+        Severity.Critical => "badge bg-danger",
+        Severity.Warning => "badge bg-warning text-dark",
+        _ => "badge bg-info"
+    };
+
+    public void Dispose()
+    {
+        Hub.OnChange -= _handler;
+    }
+}
+

